import { css } from '@emotion/core';
import {
  Anchor,
  ButtonLink,
  ButtonSizes,
  ButtonVariants,
  H3,
  H4,
  Icon,
  Layout,
  P,
  Typography,
} from 'components';
import { colors, icons, media, typography } from 'core';
import { NextPage } from 'next';
import React from 'react';

export const AllQuestionsPage: NextPage = () => {
  return (
    <Layout>
      <div className="container my-3">
        <ButtonLink variant={ButtonVariants.Flat} size={ButtonSizes.Small} className="pl-0">
          <Icon
            icon={icons.arrows.arrowBack}
            color={colors.variants.Neutral.Black}
            className="mr-1"
          />
          <P
            color={colors.variants.Neutral.Grey}
            typography={typography.variants.Element.Regular12}
          >
            Вернуться на предыдущую страницу
          </P>
        </ButtonLink>
        <div className="tw-flex-col lg:tw-flex tw-mb-8">
          <H3 className="tw-w-full"> Все вопросы </H3>
          <div className="tw-flex-col tw-w-full">
            <H3 className="mb-3">Введение в вакцинацию</H3>
            <Anchor className="tw-px-8 tw-py-4 tw-border-b tw-border-solid hover:tw-bg-purple-100 tw-border-gray-300">
              <Typography
                as="p"
                className="mt-2 mb-2"
                css={css(
                  typography.styles.headingBold22,
                  media.queryStyled([
                    typography.styles.headingBold22,
                    typography.styles.headingBold22,
                    typography.styles.headingSemiBold17,
                  ]),
                )}
              >
                Что такое вакцинация?
              </Typography>
            </Anchor>
          </div>
        </div>
      </div>
    </Layout>
  );
};
